## CRUD con localStorage

**CRUD** significa Crear, Leer, Actualizar, Eliminar (Create, Read, Update, Delete). Es el conjunto de operaciones básicas para gestionar datos. Con localStorage puedes implementar un CRUD completo sin necesitar un servidor.

### El patrón estándar

Como localStorage solo guarda strings, la estrategia es:
1. **Leer** la lista actual → `JSON.parse`
2. **Modificar** el array en memoria
3. **Guardar** de vuelta → `JSON.stringify`

```js
// Leer
const items = JSON.parse(localStorage.getItem('items') || '[]');

// Agregar
items.push({ id: Date.now(), texto: 'Nueva tarea' });

// Guardar
localStorage.setItem('items', JSON.stringify(items));
```

### Operaciones CRUD completas

```js
const CLAVE = 'tareas';

// CREATE
function agregarTarea(texto) {
  const tareas = leerTareas();
  tareas.push({ id: Date.now(), texto, completada: false });
  localStorage.setItem(CLAVE, JSON.stringify(tareas));
}

// READ
function leerTareas() {
  return JSON.parse(localStorage.getItem(CLAVE) || '[]');
}

// UPDATE
function completarTarea(id) {
  const tareas = leerTareas();
  const tarea = tareas.find(t => t.id === id);
  if (tarea) tarea.completada = true;
  localStorage.setItem(CLAVE, JSON.stringify(tareas));
}

// DELETE
function eliminarTarea(id) {
  const tareas = leerTareas().filter(t => t.id !== id);
  localStorage.setItem(CLAVE, JSON.stringify(tareas));
}
```

### Cuándo usar localStorage

✅ Preferencias del usuario, caché ligera, datos de sesión
❌ Datos sensibles (contraseñas, tokens de larga duración)
❌ Grandes volúmenes de datos (límite ~5-10 MB)

examples.code:
// Sistema de notas simple
const NOTAS_KEY = 'mis-notas';

function guardarNota(titulo, contenido) {
  const notas = JSON.parse(localStorage.getItem(NOTAS_KEY) || '[]');
  notas.push({ id: Date.now(), titulo, contenido });
  localStorage.setItem(NOTAS_KEY, JSON.stringify(notas));
  return notas;
}

function obtenerNotas() {
  return JSON.parse(localStorage.getItem(NOTAS_KEY) || '[]');
}

guardarNota('Idea', 'Aprender fetch esta semana');
guardarNota('Tarea', 'Terminar el módulo de localStorage');
console.log(obtenerNotas().length); // 2

// Actualizar un elemento — patrón map
const PREFS_KEY = 'preferencias';

function actualizarPreferencia(clave, valor) {
  const prefs = JSON.parse(localStorage.getItem(PREFS_KEY) || '{}');
  prefs[clave] = valor; // actualiza o agrega la propiedad
  localStorage.setItem(PREFS_KEY, JSON.stringify(prefs));
}

function obtenerPreferencias() {
  return JSON.parse(localStorage.getItem(PREFS_KEY) || '{}');
}

actualizarPreferencia('tema', 'oscuro');
actualizarPreferencia('idioma', 'es');
console.log(obtenerPreferencias()); // { tema: 'oscuro', idioma: 'es' }

// Eliminar — patrón filter
const ITEMS_KEY = 'items';

function eliminarItem(id) {
  const items = JSON.parse(localStorage.getItem(ITEMS_KEY) || '[]');
  const restantes = items.filter(item => item.id !== id);
  localStorage.setItem(ITEMS_KEY, JSON.stringify(restantes));
  return restantes;
}

// Poblar con datos de prueba
localStorage.setItem(ITEMS_KEY, JSON.stringify([
  { id: 1, texto: 'Estudiar JS' },
  { id: 2, texto: 'Hacer ejercicio' },
  { id: 3, texto: 'Leer un libro' }
]));

eliminarItem(2);
console.log(JSON.parse(localStorage.getItem(ITEMS_KEY)).length); // 2

