// Primero poblamos la lista para el test
localStorage.setItem('lista', JSON.stringify(['A', 'B', 'C', 'D']));

function eliminarItem(indice) {
  const lista = JSON.parse(localStorage.getItem('lista') || '[]');
  lista.splice(indice, 1);
  localStorage.setItem('lista', JSON.stringify(lista));
  return lista;
}

const resultado = eliminarItem(1); // elimina 'B'

function agregarTarea(texto) {
  const tareas = JSON.parse(localStorage.getItem('tareas') || '[]');
  tareas.push({ texto, completada: false });
  localStorage.setItem('tareas', JSON.stringify(tareas));
  return tareas;
}

function completarTarea(indice) {
  const tareas = JSON.parse(localStorage.getItem('tareas') || '[]');
  if (tareas[indice]) tareas[indice].completada = true;
  localStorage.setItem('tareas', JSON.stringify(tareas));
  return tareas;
}

function tareasCompletadas() {
  const tareas = JSON.parse(localStorage.getItem('tareas') || '[]');
  return tareas.filter(t => t.completada).length;
}

agregarTarea('Estudiar JavaScript');
agregarTarea('Hacer ejercicio');
agregarTarea('Leer un libro');
completarTarea(0);
completarTarea(2);
const completadas = tareasCompletadas();
